#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; long long R; scanf("%d %lld", &N, &R);
        long long *A = (long long*)malloc(N * sizeof(long long));
        long long *B = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &A[i]);
        for (int i = 0; i < N; ++i) scanf("%lld", &B[i]);
        long long cur = 0, ans = 0, prev = 0;
        for (int i = 0; i < N; ++i) {
            long long dt = A[i] - prev;
            long long decay = R * dt;
            if (cur > decay) cur -= decay; else cur = 0;
            cur += B[i];
            if (cur > ans) ans = cur;
            prev = A[i];
        }
        printf("%lld\n", ans);
        free(A); free(B);
    }
    return 0;
}

